var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"SPEAR_MAID_NULL_NULL","text":{"KOREA":"칫......! 내가 왜 이런 짓을 하고 있는 거람?","JPN":"チッ……！　なんで私がこんなことしなきゃいけないの？","ENG":"Hmpf! What the heck am I doing here?","TWN":"切……！我還得做這些事？"},"stage":{"bg":"BLACK","bgm":"THEMA_FLORA_MAID_SERVICE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SPEAR_MAID_NULL_NULL","text":{"KOREA":"으이씨......! 그래도 얼굴 아는 사이인데 괜히 죽기라도 했으면 찜찜하잖아!","JPN":"もう……！　なんだかんだ顔見知りだし、ここで見殺しにしたら気まずいじゃない！","ENG":"Ugh! Still, I guess I'll feel kind of bad if she dies on me... given how much time we've spent together!","TWN":"額啊……！不過好歹是認識的人，她死了我的心裡也不舒服啊！"},"stage":{"bg":"BLACK","bgm":"THEMA_FLORA_MAID_SERVICE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SPEAR_MAID_NULL_NULL","text":{"KOREA":"여엉차아앗?!","JPN":"どりゃああああ！！","ENG":"Heave-ho?!","TWN":"嘿咻？！"},"stage":{"bg":"BLACK","bgm":"THEMA_FLORA_MAID_SERVICE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SPEAR_MAID_NULL_NULL","text":{"KOREA":"하아...... 하아......","JPN":"はあ……はあ……","ENG":"*Huff... Huff...*","TWN":"哈啊……哈啊……"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_FLORA_MAID_SERVICE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SPEAR_MAID_NULL_NULL","text":{"KOREA":"릴리, 괜찮아? 일어설 수 있겠어?","JPN":"リリー、大丈夫？　立てる？","ENG":"Are you alright, Lily? Can you get up?","TWN":"莉莉，沒事吧？能站起來嗎？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_FLORA_MAID_SERVICE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"......네.","JPN":"……はい。","ENG":"Yes.","TWN":"……嗯。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_FLORA_MAID_SERVICE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"멍하니 무너지는 천장을 보고 있었는데...... 메이드장님이 구해 주셨어요.","JPN":"呆然と崩れる天井を眺めていたら……メイド長が救ってくれました。","ENG":"I was just staring blankly at the ceiling falling down on me... but then the Chief Maid saved me.","TWN":"我愣著看天花板塌下來的時候……是女僕長救了我。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_FLORA_MAID_SERVICE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"저는, 저는 대체, 그동안 무슨 짓을......","JPN":"私はこれまでなんてことを……","ENG":"What... What have I been doing this whole time?","TWN":"我、我到底，對她做了些什麼事……"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_FLORA_MAID_SERVICE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SPEAR_MAID_NULL_NULL","text":{"KOREA":"칭얼거릴 시간 없으니까 얼른 일어나!","JPN":"グズグズする時間はないから早く立って！","ENG":"There's no time to whine! Get up!","TWN":"現在沒時間讓你任性，快起來！"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_FLORA_MAID_SERVICE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SPEAR_MAID_NULL_NULL","text":{"KOREA":"그레이 리픈지 호박잎인지 하는 녀석들이 계속 나타나고 있단 말이야!","JPN":"グレーリーフなのか、カボチャの葉っぱなのか知らないけど、ずっと増えてるの！","ENG":"Those freaky Gray Leaves or whatever keep popping out of nowhere!","TWN":"格雷麗芙還是什麼的，她們不斷地冒出來了！"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_FLORA_MAID_SERVICE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SPEAR_MAID_NULL_NULL","text":{"KOREA":"여기서 죽기 싫으면 뭐든 도우라고!","JPN":"ここで死にたくなければ何でもいいから手伝って！","ENG":"You'd better help out if you don't want to croak here!","TWN":"不想死就趕緊幫忙！"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_FLORA_MAID_SERVICE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_FLORA_MAID_SERVICE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"알겠어요. 당신에게 훈계 받는 날이 올 줄은 몰랐네요.","JPN":"わかりました。あなたに説教される日が来るとは思いもしませんでした。","ENG":"Very well. I never knew the day would come when you'd be the one lecturing me.","TWN":"知道了，沒想到有一天我會受你教訓。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_FLORA_MAID_SERVICE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"그런데, 메이드장님이 아끼던 그 아이는? 당신과 같이 있지 않았나요?","JPN":"ところで、メイド長が大事にしていたあの子は？　あなたと一緒にいたのでは？","ENG":"By the way, where is the child that the Chief Maid is fond of? Wasn't she with you?","TWN":"對了，女僕長很在意的那個孩子呢？不是和你在一起嗎？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_FLORA_MAID_SERVICE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"SPEAR_MAID_NULL_NULL","text":{"KOREA":"어? 그러고 보니 진짜 없잖아?","JPN":"あれ？　そういえばいない！","ENG":"Huh? Oh, dang! She's gone!","TWN":"額？對啊，她去哪裡了？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_FLORA_MAID_SERVICE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"SPEAR_MAID_NULL_NULL","text":{"KOREA":"야! 꼬맹이! 어디 있어?!","JPN":"ねえ！　チビちゃん！　どこにいるの！？","ENG":"Hey, kid! Where are you?","TWN":"喂！小鬼！你在哪裡？！"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_FLORA_MAID_SERVICE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"멈추세요, 마스터! 어디까지 도망칠 셈이죠!","JPN":"止まってください、マスター！　どこまで逃げる気ですか！","ENG":"Halt, Master! You cannot run forever!","TWN":"不要跑了！你想逃到哪裡！"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"THEMA_FLORA_MAID_SERVICE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"흐음. 벌써 여기까지 따라왔구나. 성가시게.","JPN":"あーあ、もうここまで付いてきたの？　厄介ね。","ENG":"Hmm... So you've caught up with me already. How annoying.","TWN":"唔，這麼快就追上來了，真是麻煩。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"THEMA_FLORA_MAID_SERVICE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"하지만 부상이 심한 것 같은데, 그 몸으로 내 식물독을 버틸 수 있을까?","JPN":"でも結構辛そうに見えるけど、その体で私の植物毒に耐えられるのかしら？","ENG":"But your wounds seem pretty severe. Do you think you can withstand my poison in that state?","TWN":"你身受重傷，恐怕承受不住我的植物毒液吧？"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"THEMA_FLORA_MAID_SERVICE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"이번에야말로 내 충실한 노예로 만들어 줄게, 베로니카. 실컷 발버둥쳐 보렴.","JPN":"今度こそ私の忠実な奴隷にしてあげるわね、ベロニカ。精一杯あがいてごらんなさい。","ENG":"This time, I'll make you my loyal slave without a doubt. Resist all you want, Veronica.","TWN":"這次我要讓你徹底成為我忠實的奴隸，貝洛妮卡。你盡情掙扎吧。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"THEMA_FLORA_MAID_SERVICE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_COMBAT_ALL_MISSILE_RELOAD"},{"id":"L39_1","type":"dialog","speaker":"TONFA_MAID_NULL_NULL","text":{"KOREA":"아네모네 펀─치!","JPN":"アネモネパ～ンチ！！","ENG":"Anemone Puuunch!","TWN":"莫——妮——重——拳——！"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"THEMA_FLORA_MAID_SERVICE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_HATE"}}},"sfx":"FX_CUTSCEN_SWORD_HIT"},{"id":"L40_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"큭?! 이 교양 없는 꼬마가! 내 작품을 땅에 흘리게 해?!","JPN":"くっ！？　この教養のないガキが！　私の作品になんてことを！","ENG":"Hngh! You little brat! How dare you make me spill my masterpiece?","TWN":"咳？！沒有教養的小鬼！膽敢讓我的作品掉到地上？！"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"THEMA_FLORA_MAID_SERVICE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"TONFA_MAID_NULL_NULL","text":{"KOREA":"메이드장님을 괴롭히는 건 그만 하십셔!","JPN":"メイド長をいじめるのはやめてもらいたいっす！","ENG":"Stop bullying the Chief Maid, ma'am!","TWN":"不要再欺負女僕長大人了！"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"THEMA_FLORA_MAID_SERVICE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"TONFA_MAID_NULL_NULL","text":{"KOREA":"우리 엄니보다 못 생겼으면서 성격도 순 마귀 할망구임다!","JPN":"母ちゃんよりブスなくせに、性格まで超絶悪いババアっすね！","ENG":"You're uglier than my mama and meaner than a witch!","TWN":"你這個長的比我媽還醜，脾氣不好的魔鬼老太婆！"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"THEMA_FLORA_MAID_SERVICE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"뭐? 버르장머리 없는 꼬맹이가 뚫린 입이라고......!","JPN":"はあ？　行儀の悪いちびっ子ね……！","ENG":"What? Why, you insolent little rascal!","TWN":"什麼？你這個沒大沒小的傢伙，沒禮貌……！"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"THEMA_FLORA_MAID_SERVICE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"이 이상 달아날 곳은 없습니다, 마스터.","JPN":"もう逃げ場はありません、マスター。","ENG":"There is nowhere to run anymore, Master.","TWN":"你無處可逃了。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"THEMA_FLORA_MAID_SERVICE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"그러니 투항하세요.","JPN":"ですので投降してください。","ENG":"So surrender.","TWN":"投降吧。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"THEMA_FLORA_MAID_SERVICE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"한때 주인으로 모셨던 당신을 굳이 공격하고 싶지는 않습니다.","JPN":"一時とはいえ主として仕えていたあなたを攻撃したくはありません。","ENG":"I do not wish to assault someone whom I once served.","TWN":"我不想用我的雙手攻擊曾經的主人。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"THEMA_FLORA_MAID_SERVICE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"후훗. 걱정을 하려면 네 몸이 먼저 아닐까?","JPN":"フフッ、心配するなら自分のことを優先するべきよ？","ENG":"Hah hah, you should worry about yourself first.","TWN":"呼呼，你還是先擔心你的身體吧。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"THEMA_FLORA_MAID_SERVICE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"저건...... 공격 헬기? 처음부터 대기시켜 뒀던 건가요?","JPN":"あれは……攻撃ヘリ？　最初から待機させていたのですか？","ENG":"Is that... an attack helicopter? Have you had it standing by all along?","TWN":"那是……攻擊直升機？你一開始就把它安排在這裡？"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"THEMA_FLORA_MAID_SERVICE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L4_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"그래. 처음부터 너를 기관포로 부숴버릴 수도 있었지만, 즐거움은 아껴 둬야지.","JPN":"そうよ。最初からあなたを機関砲で粉々にすることもできたけど、楽しみは最後までとっておきたくて。","ENG":"That's right. I could have had you shred to pieces with the chain gun, but I wanted to save the fun for later.","TWN":"是的，本想一開始就用機關炮殺了你，不過好戲還是留在後頭比較好。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"THEMA_FLORA_MAID_SERVICE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"그러니 네 몸이 허락하는 짧은 시간 동안, 달콤한 추억을 많이 쌓아 두렴.","JPN":"だからその体に残されたわずかな時間で、甘い思い出をたくさん作りなさい。","ENG":"So make many sweet memories in the short while that your body allows it.","TWN":"趁你的身體可以短暫地感受一切，盡情享受吧。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"THEMA_FLORA_MAID_SERVICE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"너를 꺾어 버릴 때 후회가 남지 않도록.","JPN":"あなたをむしる時に後悔が残らないように。","ENG":"Otherwise, you'll regret it when I finally pluck you.","TWN":"好讓我折了你的時候，不會留下遺憾。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"THEMA_FLORA_MAID_SERVICE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"하지만, 헬기의 저 사람은......","JPN":"ですが、ヘリに乗っているあの人は……","ENG":"But that pilot on the helicopter...","TWN":"可是，直升機上的那個人……"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"THEMA_FLORA_MAID_SERVICE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L11_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"놀라는 표정도 꽤 신선하구나.","JPN":"驚く顔を見るのもなかなか新鮮ね。","ENG":"Well, it's refreshing to see you so surprised.","TWN":"難得看到你驚訝的表情。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"THEMA_FLORA_MAID_SERVICE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"그럼 잘 지내고 있으렴. 베로니카.","JPN":"それじゃあ元気でね、ベロニカ。","ENG":"Farewell then, Veronica.","TWN":"好自為之吧，貝洛妮卡。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"THEMA_FLORA_MAID_SERVICE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_QM","text":{"KOREA":"수고하셨습니다. 어디로 모실까요?","JPN":"お疲れ様でした。どちらにご案内しましょうか。","ENG":"Welcome aboard, ma'am. Where shall I take you?","TWN":"辛苦了，接下來我們去哪裡？"},"stage":{"bg":"HELI_NIGHT","bgm":"THEMA_FLORA_MAID_SERVICE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"가까운 세이프 하우스로 가자꾸나. 오랜만의 외출이라 몸이 노곤하네.","JPN":"近くのセーフハウスに行って。久しぶりの外出で疲れちゃったわ。","ENG":"Let's go to the nearest safe house. I haven't been out in a while and it's gotten me quite weary.","TWN":"去最近的安全據點吧，好久沒出來了，身體有點累。"},"stage":{"bg":"HELI_NIGHT","bgm":"THEMA_FLORA_MAID_SERVICE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_QM","text":{"KOREA":"그래요? 피로를 풀기 좋은 시설을 아는데, 그리로 모실까요?","JPN":"そうでしたか。疲れを癒すのにピッタリな施設を知っていますが、そちらにご案内しましょうか？","ENG":"Is that right? I happen to know a great place to take a load off. Should I take you there?","TWN":"是嗎？我剛好知道一個可以緩解疲勞的地方，要不去那裡吧？"},"stage":{"bg":"HELI_NIGHT","bgm":"THEMA_FLORA_MAID_SERVICE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"조종이나 할 것이지 경망스럽게 구는구나. 어딘데 그러니?","JPN":"あなたの仕事は操縦のはずよ。許可なしで喋らないで。で、その場所って？","ENG":"You run your mouth far too much for a pilot. Fine, where is this place?","TWN":"好好駕駛，別這麼冒冒失失的。你說的地方是哪裡？"},"stage":{"bg":"HELI_NIGHT","bgm":"THEMA_FLORA_MAID_SERVICE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"그라운드 원 수용소입니다. <color=#ffd34c>승객</color>님.","JPN":"グラウンド・ワン収容所です。<color=#ffd34c>お客様</color>。","ENG":"Ground One Penitentiary, <color=#ffd34c>ma'am</color>.","TWN":"G1集中營，親愛的<color=#ffd34c>乘客</color>。"},"stage":{"bg":"HELI_NIGHT","bgm":"THEMA_FLORA_MAID_SERVICE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"원하지 않으셔도 목적지까지 편안히 모실 테니 손가락 하나 까딱 말고 계시길.","JPN":"お望みでなくても、目的地まで安全にご案内するので大人しくついてきてくださいね。","ENG":"Don't worry, I'll make sure you get to the destination, whether you want it or not.","TWN":"你不想去也得去，我會安全護送你到目的地，所以最好不要輕舉妄動。"},"stage":{"bg":"HELI_NIGHT","bgm":"THEMA_FLORA_MAID_SERVICE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"......베로니카의 새 주인이 보냈나 보구나.","JPN":"……ベロニカの新しい主の仕業か。","ENG":"... Veronica's new master must have sent you.","TWN":"……是貝洛妮卡的新主人派你過來的吧。"},"stage":{"bg":"HELI_NIGHT","bgm":"THEMA_FLORA_MAID_SERVICE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"지금 겨눈 총, 뒷감당은 할 수 있을 거 같니?","JPN":"その銃口を私に向けることの意味はわかっているのかしら？","ENG":"You think you can handle the consequences of pointing that gun at me?","TWN":"敢用槍指著我，你承擔得起後果嗎？"},"stage":{"bg":"HELI_NIGHT","bgm":"THEMA_FLORA_MAID_SERVICE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"감당은 그쪽이 먼저 해야지.","JPN":"まだ状況が把握できていないみたいね。","ENG":"You'll have to worry about the consequences you have to face first.","TWN":"你還是擔心你自己吧。"},"stage":{"bg":"HELI_NIGHT","bgm":"THEMA_FLORA_MAID_SERVICE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"관리국 통합 정보부가 수용소에서 댁을 애타게 기다리고 있으니까.","JPN":"管理局総合情報部が収容所であなたのことを、首を長くして待っているから。","ENG":"The entire intelligence apparatus of the Administration is just dying to see you there.","TWN":"管理局綜合情報部正在集中營等著你呢。"},"stage":{"bg":"HELI_NIGHT","bgm":"THEMA_FLORA_MAID_SERVICE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"......흥.","JPN":"……フン。","ENG":"Hmpf.","TWN":"……哼。"},"stage":{"bg":"HELI_NIGHT","bgm":"THEMA_FLORA_MAID_SERVICE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_DESPAIR"},"R":null}}}]`);export{e as default};